'use client';

import { motion } from 'framer-motion';
import Link from 'next/link';
import {
  Brain,
  Layers,
  Compass,
  Library,
  Heart,
  Search,
} from 'lucide-react';

const items = [
  { label: 'Quiz du jour', icon: Brain, href: '/quiz', color: 'text-primary-400', bg: 'bg-primary-500/10' },
  { label: 'Flashcards', icon: Layers, href: '/flashcards', color: 'text-gold-400', bg: 'bg-gold-500/10' },
  { label: 'Thèmes', icon: Compass, href: '/explore', color: 'text-teal-400', bg: 'bg-teal-500/10' },
  { label: 'Bibliothèque', icon: Library, href: '/library', color: 'text-blue-400', bg: 'bg-blue-500/10' },
  { label: 'Favoris', icon: Heart, href: '/favorites', color: 'text-red-400', bg: 'bg-red-500/10' },
  { label: 'Recherche', icon: Search, href: '/search', color: 'text-purple-400', bg: 'bg-purple-500/10' },
];

const container = {
  hidden: {},
  visible: {
    transition: { staggerChildren: 0.06 },
  },
};

const item = {
  hidden: { opacity: 0, scale: 0.9 },
  visible: { opacity: 1, scale: 1, transition: { duration: 0.35 } },
};

export default function QuickAccess() {
  return (
    <motion.div
      variants={container}
      initial="hidden"
      animate="visible"
      className="grid grid-cols-3 sm:grid-cols-6 gap-3"
    >
      {items.map((entry) => {
        const Icon = entry.icon;
        return (
          <motion.div key={entry.href} variants={item}>
            <Link
              href={entry.href}
              className="flex flex-col items-center gap-2.5 rounded-2xl p-4 transition-all duration-200 hover:scale-[1.04] active:scale-95"
              style={{
                background: 'var(--bg-card)',
                border: '1px solid var(--border-subtle)',
              }}
            >
              <div className={`flex items-center justify-center w-10 h-10 rounded-xl ${entry.bg}`}>
                <Icon size={20} className={entry.color} />
              </div>
              <span
                className="text-xs font-medium text-center leading-tight"
                style={{ color: 'var(--text-secondary)' }}
              >
                {entry.label}
              </span>
            </Link>
          </motion.div>
        );
      })}
    </motion.div>
  );
}
