'use client';

import { motion } from 'framer-motion';
import Link from 'next/link';
import { themes } from '@/data/themes';
import Card from '@/components/ui/Card';

const container = {
  hidden: {},
  visible: { transition: { staggerChildren: 0.07 } },
};

const item = {
  hidden: { opacity: 0, y: 14 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.4 } },
};

export default function ThemePreview() {
  const displayThemes = themes.slice(0, 6);

  if (displayThemes.length === 0) return null;

  return (
    <motion.div
      variants={container}
      initial="hidden"
      animate="visible"
      className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide md:grid md:grid-cols-3 md:overflow-visible md:pb-0"
    >
      {displayThemes.map((theme) => (
        <motion.div
          key={theme.id}
          variants={item}
          className="min-w-[200px] md:min-w-0"
        >
          <Link href={`/explore/${theme.id}`}>
            <Card glowColor="green" className="p-4 h-full">
              <div className="space-y-3">
                {/* Icon circle */}
                <div
                  className="w-9 h-9 rounded-xl flex items-center justify-center text-sm font-bold"
                  style={{
                    backgroundColor: `${theme.color}20`,
                    color: theme.color,
                  }}
                >
                  {theme.titleAr?.charAt(0) ?? '★'}
                </div>

                {/* Title & count */}
                <div>
                  <h3
                    className="text-sm font-semibold leading-snug line-clamp-1"
                    style={{ color: 'var(--text-primary)' }}
                  >
                    {theme.title}
                  </h3>
                  <p
                    className="text-xs mt-0.5"
                    style={{ color: 'var(--text-muted)' }}
                  >
                    {theme.contentCount} contenu{theme.contentCount > 1 ? 's' : ''}
                  </p>
                </div>

                {/* Progress bar */}
                {theme.progress != null && theme.progress > 0 && (
                  <div className="space-y-1">
                    <div
                      className="h-1.5 rounded-full overflow-hidden"
                      style={{ background: 'var(--border-subtle)' }}
                    >
                      <div
                        className="h-full rounded-full transition-all duration-500"
                        style={{
                          width: `${theme.progress}%`,
                          backgroundColor: theme.color,
                        }}
                      />
                    </div>
                    <p className="text-[10px] text-right" style={{ color: 'var(--text-muted)' }}>
                      {theme.progress}%
                    </p>
                  </div>
                )}
              </div>
            </Card>
          </Link>
        </motion.div>
      ))}
    </motion.div>
  );
}
