'use client';

import { motion } from 'framer-motion';
import Link from 'next/link';
import { books } from '@/data/books';
import Card from '@/components/ui/Card';
import Badge from '@/components/ui/Badge';

const statusConfig: Record<string, { label: string; variant: 'green' | 'gold' | 'default' }> = {
  read: { label: 'Lu', variant: 'green' },
  reading: { label: 'En cours', variant: 'gold' },
  'to-read': { label: 'À lire', variant: 'default' },
};

const coverColors = ['#3aaa60', '#d4991a', '#24ad9d', '#6366f1', '#ec4899', '#8b5cf6'];

const container = {
  hidden: {},
  visible: { transition: { staggerChildren: 0.07 } },
};

const item = {
  hidden: { opacity: 0, y: 14 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.4 } },
};

export default function RecentBooks() {
  const recentBooks = [...books]
    .sort((a, b) => new Date(b.addedAt).getTime() - new Date(a.addedAt).getTime())
    .slice(0, 4);

  if (recentBooks.length === 0) return null;

  return (
    <motion.div
      variants={container}
      initial="hidden"
      animate="visible"
      className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide sm:grid sm:grid-cols-2 md:grid-cols-4 sm:overflow-visible sm:pb-0"
    >
      {recentBooks.map((book, idx) => {
        const config = statusConfig[book.status] ?? statusConfig['to-read'];
        const initials = book.title
          .split(' ')
          .slice(0, 2)
          .map((w) => w.charAt(0))
          .join('')
          .toUpperCase();

        return (
          <motion.div
            key={book.id}
            variants={item}
            className="min-w-[160px] sm:min-w-0"
          >
            <Link href={`/library/${book.id}`}>
              <Card glowColor="gold" className="p-4 h-full">
                <div className="space-y-3">
                  {/* Cover placeholder */}
                  <div
                    className="w-full aspect-[3/4] rounded-xl flex items-center justify-center text-lg font-bold text-white/90"
                    style={{
                      backgroundColor: `${coverColors[idx % coverColors.length]}20`,
                      color: coverColors[idx % coverColors.length],
                    }}
                  >
                    {initials}
                  </div>

                  {/* Info */}
                  <div className="space-y-1.5">
                    <h3
                      className="text-sm font-semibold leading-snug line-clamp-2"
                      style={{ color: 'var(--text-primary)' }}
                    >
                      {book.title}
                    </h3>
                    <p
                      className="text-xs line-clamp-1"
                      style={{ color: 'var(--text-muted)' }}
                    >
                      {book.author}
                    </p>
                    <Badge variant={config.variant} size="sm">
                      {config.label}
                    </Badge>
                  </div>
                </div>
              </Card>
            </Link>
          </motion.div>
        );
      })}
    </motion.div>
  );
}
