'use client';

import { motion } from 'framer-motion';
import { Share2, BookOpen, Quote, Bell, ScrollText } from 'lucide-react';
import { dailyReminders } from '@/data/daily';
import Badge from '@/components/ui/Badge';

const typeConfig: Record<string, { label: string; variant: 'gold' | 'green' | 'teal' | 'blue'; icon: React.ElementType }> = {
  verse: { label: 'Verset', variant: 'green', icon: BookOpen },
  hadith: { label: 'Hadith', variant: 'gold', icon: ScrollText },
  quote: { label: 'Citation', variant: 'teal', icon: Quote },
  reminder: { label: 'Rappel', variant: 'blue', icon: Bell },
};

export default function DailyReminder() {
  if (dailyReminders.length === 0) return null;

  const dayIndex = new Date().getDay() % dailyReminders.length;
  const reminder = dailyReminders[dayIndex];
  const config = typeConfig[reminder.type] ?? typeConfig.reminder;
  const TypeIcon = config.icon;

  return (
    <motion.div
      initial={{ opacity: 0, y: 16 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5, delay: 0.3 }}
      className="relative rounded-2xl p-5 sm:p-6 overflow-hidden"
      style={{
        background: 'var(--bg-card)',
        border: '1px solid var(--border-subtle)',
      }}
    >
      {/* Gold accent top border */}
      <div className="absolute top-0 left-0 right-0 h-0.5 bg-gradient-to-r from-transparent via-gold-400 to-transparent" />

      {/* Subtle glow */}
      <div className="absolute -top-20 -right-20 w-40 h-40 rounded-full bg-gold-500/6 blur-3xl" />

      <div className="relative space-y-4">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <TypeIcon size={16} className="text-gold-400" />
            <Badge variant={config.variant} size="sm">
              {config.label}
            </Badge>
          </div>
          <button
            type="button"
            aria-label="Partager"
            className="p-2 rounded-xl transition-colors duration-200 hover:bg-white/5"
            style={{ color: 'var(--text-muted)' }}
          >
            <Share2 size={16} />
          </button>
        </div>

        {/* Arabic text */}
        {reminder.contentAr && (
          <p
            className="text-lg sm:text-xl font-semibold leading-relaxed text-right"
            dir="rtl"
            lang="ar"
            style={{ color: 'var(--text-primary)', fontFamily: 'serif' }}
          >
            {reminder.contentAr}
          </p>
        )}

        {/* French content */}
        <p
          className="text-sm sm:text-base leading-relaxed"
          style={{ color: 'var(--text-secondary)' }}
        >
          {reminder.content}
        </p>

        {/* Source */}
        {reminder.source && (
          <p className="text-xs font-medium text-gold-500/70 pt-1">
            — {reminder.source}
          </p>
        )}
      </div>
    </motion.div>
  );
}
